1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type Step = { op: string; items?: Item[]; policy?: number; incident?: Incident };
5	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
6	type Scenario = { customer: Customer; steps: Step[] };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	const CAP_MULTIPLIER = 2;
10	
11	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const insuranceValueForItem = (item: Item): number =>
21	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
22	
23	const insuranceSumForItems = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + insuranceValueForItem(item), 0);
25	
26	const PROCESSING_FEE = 5;
27	
28	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PRICE = 60;
40	
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	
45	const LOYALTY_DISCOUNT_RATE = 0.2;
46	const LOYALTY_MIN_YEARS = 2;
47	
48	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	
51	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	
55	const isHighlyEnchanted = (item: Item): boolean =>
56	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
57	
58	const itemSurchargeRate = (item: Item): number =>
59	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
60	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
61	
62	const premiumForItem = (item: Item): number =>
63	  baseForType(item.type) * (1 + itemSurchargeRate(item));
64	
65	const countItemsOfType = (items: Item[], type: string): number =>
66	  items.filter((item) => item.type === type).length;
67	
68	const premiumForComponentType = (items: Item[], type: string): number => {
69	  const count = countItemsOfType(items, type);
70	  return count === COMPONENT_BLOCK_SIZE
71	    ? COMPONENT_BLOCK_PRICE
72	    : count * baseForType(type);
73	};
74	
75	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
76	
77	const totalForItems = (items: Item[], priceForItem: (item: Item) => number): number => {
78	  const componentsTotal = COMPONENT_TYPES.reduce(
79	    (sum, type) => sum + premiumForComponentType(items, type),
80	    0,
81	  );
82	  const nonComponentsTotal = items
83	    .filter((item) => !isComponent(item))
84	    .reduce((sum, item) => sum + priceForItem(item), 0);
85	  return componentsTotal + nonComponentsTotal;
86	};
87	
88	const itemsTotalWithItemSurcharges = (items: Item[]): number =>
89	  totalForItems(items, premiumForItem);
90	
91	const itemsTotalBasePricesOnly = (items: Item[]): number =>
92	  totalForItems(items, (item) => baseForType(item.type));
93	
94	const loyaltyRate = (customer: Customer): number =>
95	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
96	
97	const firstInsuranceRate = (customer: Customer): number =>
98	  customer.previousContracts !== undefined ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
99	
100	const followUpRate = (customer: Customer): number =>
101	  (customer.previousContracts ?? 0) >= 1 ? -FOLLOW_UP_DISCOUNT_RATE : 0;
102	
103	const policyAdjustmentRate = (customer: Customer): number =>
104	  loyaltyRate(customer) + firstInsuranceRate(customer) + followUpRate(customer);
105	
106	const roundUpInMHPCOFavor = (value: number): number => Math.ceil(value);
107	
108	const quotePremium = (items: Item[], customer: Customer): number => {
109	  const itemsTotal = itemsTotalWithItemSurcharges(items);
110	  const policyBase = itemsTotalBasePricesOnly(items);
111	  const policyAdjustment = policyBase * policyAdjustmentRate(customer);
112	  return roundUpInMHPCOFavor(itemsTotal + policyAdjustment + PROCESSING_FEE);
113	};
114	
115	type QuoteResult = { premium: number };
116	type ClaimResult = { payout: number; remainingCap: number };
117	type StepResult = QuoteResult | ClaimResult;
118	
119	type PolicyState = { items: Item[]; cap: number; remainingCap: number };
120	
121	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
122	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
123	
124	const reimbursementForDamage = (damage: Damage, items: Item[]): number => {
125	  const item = items.find((i) => i.type === damage.itemType);
126	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
127	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
128	  }
129	  return damage.amount;
130	};
131	
132	const payoutForDamage = (damage: Damage, items: Item[]): number =>
133	  reimbursementForDamage(damage, items) - DEDUCTIBLE_PER_DAMAGE;
134	
135	const payoutForClaim = (incident: Incident, items: Item[]): number =>
136	  incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage, items), 0);
137	
138	const openPolicy = (items: Item[]): PolicyState => {
139	  const cap = CAP_MULTIPLIER * insuranceSumForItems(items);
140	  return { items, cap, remainingCap: cap };
141	};
142	
143	const handleQuote = (
144	  step: Step,
145	  customer: Customer,
146	  policies: PolicyState[],
147	): QuoteResult => {
148	  const items = step.items ?? [];
149	  policies.push(openPolicy(items));
150	  return { premium: quotePremium(items, customer) };
151	};
152	
153	const handleClaim = (step: Step, policies: PolicyState[]): ClaimResult => {
154	  const policy = policies[step.policy as number];
155	  const payout = payoutForClaim(step.incident as Incident, policy.items);
156	  policy.remainingCap -= payout;
157	  return { payout, remainingCap: policy.remainingCap };
158	};
159	
160	export const runScenario = (input: unknown): { results: StepResult[] } => {
161	  const { customer, steps } = input as Scenario;
162	  const policies: PolicyState[] = [];
163	  const results: StepResult[] = steps.map((step) =>
164	    step.op === "quote"
165	      ? handleQuote(step, customer, policies)
166	      : handleClaim(step, policies),
167	  );
168	  return { results };
169	};
